function solve(s: string, order: number[], k: number): number {
    const n = s.length;
    let replaced = new Array(n).fill(false);
    let totalValidSubstrings = 0;

    // Precompute the positions of '*' in the order
    const starPositions: number[] = [];
    for (let i = 0; i < n; i++) {
        starPositions.push(order[i]);
    }

    // Function to count the number of valid substrings
    function countValidSubstrings() {
        let count = 0;
        const starIndices = starPositions.filter(pos => replaced[pos]);
        if (starIndices.length === 0) return 0;

        // For each star, calculate the number of substrings that include it
        for (let i = 0; i < starIndices.length; i++) {
            let star = starIndices[i];
            let left = star;
            while (left >= 0 && !replaced[left]) left--;
            let right = star;
            while (right < n && !replaced[right]) right++;
            count += (star - left) * (right - star);
        }

        // Subtract overlaps (substrings that include more than one star)
        // This is a simplified approach and may not be accurate for all cases
        // For the purpose of this problem, we'll use a more efficient approach
        // by considering the gaps between stars

        // Re-calculate using gaps between stars
        let prevStar = -1;
        let total = 0;
        for (let i = 0; i < starIndices.length; i++) {
            let star = starIndices[i];
            let gap = star - prevStar - 1;
            total += gap * (gap + 1) / 2;
            prevStar = star;
        }
        total += (n - prevStar - 1) * (n - prevStar) / 2;
        return total;
    }

    // Binary search for the minimum time t
    let left = 0, right = n;
    let answer = -1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        // Replace the first mid elements in order
        for (let i = 0; i < mid; i++) {
            replaced[order[i]] = true;
        }

        const currentCount = countValidSubstrings();
        if (currentCount >= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }

        // Reset replaced array for next iteration
        for (let i = 0; i < mid; i++) {
            replaced[order[i]] = false;
        }
    }

    return answer;
}

